#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline void pt(const int &p,const char &c='\n'){print(p<0?putchar('-'),-p:p);putchar(c);}
const int N=2e5+10;int a[N],n;
//namespace LCT
//{
	int ch[N][2],fa[N],sz[N];
	inline void update(const int &p){sz[p]=sz[ch[p][0]]+sz[ch[p][1]]+1;}
	inline bool nrt(const int &p){return ch[fa[p]][0]==p||ch[fa[p]][1]==p;}
	inline void rotate(const int &x)
	{
		int y=fa[x],z=fa[y];const bool &k=ch[y][1]==x;
		if(nrt(y))ch[z][ch[z][1]==y]=x;int w=ch[x][!k];ch[ch[x][!k]=y][k]=w;
		if(w)fa[w]=y;fa[fa[y]=x]=z;update(y);
	}
	inline void splay(const int &x){const int &y=fa[x];while(nrt(x)){if(nrt(y))rotate((ch[fa[y]][0]==y)^(ch[y][0]==x)?x:y);rotate(x);}update(x);}
	inline void access(int x){for(int y=0;x;x=fa[y=x])splay(x),ch[x][1]=y,update(x);}
//}
int main()
{
	n=read();rep(1,n,i){sz[i]=1;int d=read();if(i+d<=n)fa[i]=i+d;}
	int Q=read(),x,y;while(Q--)switch(read())
	{
		case 1: x=read()+1;access(x);splay(x);pt(sz[x]);break;
		case 2: x=read()+1;y=read();access(x);splay(x);ch[x][0]=fa[ch[x][0]]=0;if(x+y<=n)fa[x]=x+y;update(x);
	}
}
